{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Un pehz diwidefmtis Gad-\ndeem/ kad Salamans tohs diwi\nNammus bij ustaifijis/prohti ta\nKUNGĀ Nammu/ un ta Kehni-\nna Namnu/"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Par ko Irains tas Keh-\nninsch no Tirus Salamanam\nZeedra-Kohkus/un Preedes-Koh-\nkus/un Seltu pehz wiꞥſch winna\nEegrribbeschannu bij atweddig/ tad\ndewe tas Kehninsch Salamans\nIramam diwidetmits Pilsfah-\ntus eekſch tahs Semmes Ga-\nlilejas."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Un Irains iegabje tohs\nPilsfahthus apshukhoht/ ko Sala-\nmans tam bij dewis/bet tee win-\nxam ne patikke."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Tapehz fazzija wiꞥſch:\nKas tee tahdi Pilsjahti mans\nBrahli/ ko tu man eſti dewis?\nun wiꞥſch nofauze to Semmi\nKabul/ lihds fchodeen."
    },
    {
      "n": 14,
      "column": "left",
      "text": "Un Irains bij tam Kehni-\nxam fuhtijs ſimts un diwide-\nmits Talentus Selta."
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un tik dauds Mefiu fa-\ndsinne tas Kehninsch Salamans/\nta wiꞥſch ustaifitu ta KUNGĀ\nNamnu/un fawu patchu Nam-\nnu/ un Milln/un Jerufalemes\nMuhkus/ un Azoru/ un Megid-\ndu/un Gaseru."
    },
    {
      "n": 16,
      "column": "left",
      "text": "Jo Warauis tas Eqiptes\nKehninsch bij nahzis/ un Gaseru\nusnehmis/ un ar Ugguni fade-\ndsinojs/ un tohs Kananitens/\nkas tai Pilsjahta dſthwoja no-\nfawis/ un bij fawai Meitai Sa-\nlamana Seewaito eedahwanajs."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Ta uſtaifija Salamans\nGaseru/ un to letjas Bet-Obronu."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Baleatu/ un Tama-\nru eekſch Tukſneses tai Semmē/"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Ir wiﬀus Spihkezu Pils-\nfahthus/ kas Salamanam peeder-\nreja/ un tohs Riattu Pilsfahthus/\nun to Jahtneeku Pilsfahthus/ un\nko wiꞥſch Prahta nehine uſtai-\nfiht Jerufalemē/ un us to Libba-\nnu/ un wiﬀas fawas Waldischa-\nnas Semmē."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un wiﬀus tohs atliffu-\nschus Landis no teem Amorite-\nreem/Getitereem/ Weresitereem/\nGewitereem/ un Jebusitereem/\nkas no teem Ifraēta Behrnein\nne bija."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Winnu Behrnis/ kas\npehz winneem tai Semmē bij\natliffuschis/ ko tee Ifraēta Behr-\nni ne warreja isdeldcht/tohs spee-\nde Salamans pee Mefiu Doh-\nſchanas/ ka tee Wehrgi dohd/\nlihds fchodeen."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Bet no Ifraēta Behr-\nnem ne darrija Salamans ne\nweenu Wehrgu/ bet tee bija Kar-\nra-Wihri/ un winnam par Kal-\npeem/ un winna Leeli-Kungi/\nun winna Kapteines/ un Wirf-\nneeki pahr winna Ratteem un\npahr winna Jahtneekem."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un to Pawaldneeku pee\nSalamana Darveem bija prez-\nfints un peezdefmits/ kas pahr\nteem Landim waldija/ kas to\nDarbu vadarrija."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Bet Warauis Meita gah.\nje no Dahvida Pils augſcham\nfawa"
    }
  ],
  "confidence": "high",
  "notes": ""
}
